{
  "name": "StoryVerse - Creative Blogging Platform",
  "description": "A feature-rich blogging and storytelling platform with real-time likes, comments, social sharing, and a dynamic user badge ranking system based on engagement."
}

export interface User {
  id: string;
  username: string;
  avatar: string;
  totalLikes: number;
  badge: BadgeTier;
}

export enum BadgeTier {
  NOVICE = 'Novice',
  BRONZE = 'Bronze',
  SILVER = 'Silver',
  GOLD = 'Gold',
  PLATINUM = 'Platinum'
}

export interface Comment {
  id: string;
  userId: string;
  username: string;
  content: string;
  createdAt: string;
}

export interface Post {
  id: string;
  userId: string;
  username: string;
  title: string;
  content: string;
  likes: number;
  comments: Comment[];
  shares: number;
  createdAt: string;
  userAvatar: string;
}

export interface AppState {
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  searchQuery: string;
}

import React from 'react';

export const BADGE_CONFIG = {
  Novice: { color: 'text-slate-400', bg: 'bg-slate-100', threshold: 0 },
  Bronze: { color: 'text-amber-600', bg: 'bg-amber-100', threshold: 5 },
  Silver: { color: 'text-slate-500', bg: 'bg-slate-200', threshold: 25 },
  Gold: { color: 'text-yellow-500', bg: 'bg-yellow-100', threshold: 100 },
  Platinum: { color: 'text-indigo-600', bg: 'bg-indigo-100', threshold: 500 },
};

export const LOGO_SVG = (
  <svg width="40" height="40" viewBox="0 0 100 100" className="mr-2">
    <rect x="20" y="20" width="60" height="60" rx="8" fill="white" stroke="black" strokeWidth="4" />
    <path d="M40 40 H60 M40 50 H60 M40 60 H50" stroke="black" strokeWidth="4" strokeLinecap="round" />
  </svg>
);

import { Post, User, BadgeTier, Comment } from '../types';

const POSTS_KEY = 'storyverse_posts';
const USERS_KEY = 'storyverse_users';
const SESSION_KEY = 'storyverse_session';

const INITIAL_USERS: User[] = [
  { id: '1', username: 'WordSmith', avatar: 'https://picsum.photos/seed/user1/100', totalLikes: 120, badge: BadgeTier.GOLD },
  { id: '2', username: 'InkMaster', avatar: 'https://picsum.photos/seed/user2/100', totalLikes: 45, badge: BadgeTier.SILVER },
];

const INITIAL_POSTS: Post[] = [
  {
    id: 'p1',
    userId: '1',
    username: 'WordSmith',
    title: 'The Echoes of Time',
    content: 'In the heart of the ancient forest, time doesn\'t flow like a river; it swirls like an eddy in a stream. Every leaf tells a story of a century passed, and every breeze whispers secrets of what is to come...',
    likes: 85,
    shares: 12,
    comments: [],
    createdAt: new Date().toISOString(),
    userAvatar: 'https://picsum.photos/seed/user1/100'
  },
  {
    id: 'p2',
    userId: '2',
    username: 'InkMaster',
    title: 'Neon Dreams in Kyoto',
    content: 'Walking through the Gion district at midnight, the rain reflected a kaleidoscope of colors from the lanterns. It felt like walking through a dream where the past and future met for coffee.',
    likes: 32,
    shares: 5,
    comments: [],
    createdAt: new Date().toISOString(),
    userAvatar: 'https://picsum.photos/seed/user2/100'
  }
];

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

export const db = {
  getPosts: (): Post[] => {
    const data = localStorage.getItem(POSTS_KEY);
    if (!data) {
      localStorage.setItem(POSTS_KEY, JSON.stringify(INITIAL_POSTS));
      return INITIAL_POSTS;
    }
    return JSON.parse(data);
  },

  savePost: (post: Post) => {
    const posts = db.getPosts();
    posts.unshift(post);
    localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
  },

  updatePost: (updatedPost: Post) => {
    const posts = db.getPosts();
    const index = posts.findIndex(p => p.id === updatedPost.id);
    if (index !== -1) {
      posts[index] = updatedPost;
      localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
    }
  },

  getUsers: (): User[] => {
    const data = localStorage.getItem(USERS_KEY);
    if (!data) {
      localStorage.setItem(USERS_KEY, JSON.stringify(INITIAL_USERS));
      return INITIAL_USERS;
    }
    return JSON.parse(data);
  },

  updateUserLikes: (userId: string, delta: number) => {
    const users = db.getUsers();
    const user = users.find(u => u.id === userId);
    if (user) {
      user.totalLikes += delta;
      user.badge = getBadge(user.totalLikes);
      localStorage.setItem(USERS_KEY, JSON.stringify(users));
    }
  },

  getCurrentUser: (): User | null => {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  login: (username: string): User => {
    const users = db.getUsers();
    let user = users.find(u => u.username.toLowerCase() === username.toLowerCase());
    if (!user) {
      user = {
        id: Math.random().toString(36).substr(2, 9),
        username,
        avatar: `https://picsum.photos/seed/${username}/100`,
        totalLikes: 0,
        badge: BadgeTier.NOVICE
      };
      users.push(user);
      localStorage.setItem(USERS_KEY, JSON.stringify(users));
    }
    localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return user;
  },

  logout: () => {
    localStorage.removeItem(SESSION_KEY);
  }
};

import React from 'react';
import { BadgeTier } from '../types';
import { BADGE_CONFIG } from '../constants';

interface BadgeIconProps {
  tier: BadgeTier;
  size?: 'sm' | 'md';
}

export const BadgeIcon: React.FC<BadgeIconProps> = ({ tier, size = 'sm' }) => {
  const config = BADGE_CONFIG[tier as keyof typeof BADGE_CONFIG];
  const sizeClasses = size === 'sm' ? 'px-2 py-0.5 text-[10px]' : 'px-3 py-1 text-xs';

  return (
    <span className={`${config.bg} ${config.color} ${sizeClasses} font-bold rounded-full uppercase tracking-wider border border-current opacity-90`}>
      {tier}
    </span>
  );
};

import React, { useState } from 'react';
import { User } from '../types';
import { LOGO_SVG } from '../constants';

interface NavbarProps {
  user: User | null;
  isDarkMode: boolean;
  toggleDarkMode: () => void;
  onSearch: (query: string) => void;
  onLogout: () => void;
  onNavigate: (page: 'home' | 'create' | 'login' | 'my-stories') => void;
}

export const Navbar: React.FC<NavbarProps> = ({ 
  user, 
  isDarkMode, 
  toggleDarkMode, 
  onSearch, 
  onLogout,
  onNavigate 
}) => {
  const [query, setQuery] = useState('');

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    onSearch(query);
  };

  return (
    <nav className={`sticky top-0 z-50 w-full border-b transition-colors duration-300 ${
      isDarkMode ? 'bg-slate-900 border-slate-800 text-white' : 'bg-white border-slate-200 text-slate-900'
    }`}>
      <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between gap-4">
        {/* Logo */}
        <div 
          className="flex items-center cursor-pointer hover:opacity-80 transition-opacity shrink-0"
          onClick={() => onNavigate('home')}
        >
          <div className={`${isDarkMode ? 'invert' : ''}`}>
            {LOGO_SVG}
          </div>
          <span className="font-serif text-xl font-bold hidden sm:block">StoryVerse</span>
        </div>

        {/* Search */}
        <form onSubmit={handleSearch} className="flex-1 max-w-md relative group">
          <input
            type="text"
            placeholder="Search stories..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className={`w-full pl-4 pr-20 py-2 rounded-full border outline-none transition-all ${
              isDarkMode 
                ? 'bg-slate-800 border-slate-700 focus:border-indigo-500' 
                : 'bg-slate-50 border-slate-200 focus:border-blue-500'
            }`}
          />
          <button 
            type="submit"
            className="absolute right-1 top-1 bottom-1 px-4 bg-cyan-600 hover:bg-cyan-700 text-white text-sm font-bold rounded-full transition-colors"
          >
            Search
          </button>
        </form>

        {/* Links & Tools */}
        <div className="flex items-center gap-4">
          <div className="hidden md:flex items-center gap-4 text-sm font-medium">
            {user ? (
              <>
                <button onClick={() => onNavigate('home')} className="hover:text-blue-500">Home</button>
                <button onClick={() => onNavigate('create')} className="hover:text-blue-500">New Post</button>
                <button onClick={() => onNavigate('my-stories')} className="hover:text-blue-500">My Stories</button>
                <button onClick={onLogout} className="hover:text-red-500">Logout</button>
              </>
            ) : (
              <>
                <button onClick={() => onNavigate('login')} className="hover:text-blue-500">Login</button>
                <button onClick={() => onNavigate('login')} className="hover:text-blue-500">Register</button>
              </>
            )}
          </div>

          <button
            onClick={toggleDarkMode}
            className={`p-2 rounded-full transition-colors ${
              isDarkMode ? 'bg-slate-800 hover:bg-slate-700' : 'bg-slate-100 hover:bg-slate-200'
            }`}
          >
            {isDarkMode ? '☀️' : '🌙'}
          </button>

          {user && (
            <div className="flex items-center gap-2 border-l pl-4 border-slate-700/20">
              <img src={user.avatar} className="w-8 h-8 rounded-full border-2 border-indigo-500" alt="Avatar" />
              <div className="hidden lg:block">
                <p className="text-xs font-bold leading-none">{user.username}</p>
                <p className="text-[10px] text-slate-500">{user.badge}</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </nav>
  );
};

import React, { useState } from 'react';
import { Post, User } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, currentUser, isDarkMode, onPostUpdate }) => {
  const [commentText, setCommentText] = useState('');
  const [showComments, setShowComments] = useState(false);

  const handleLike = () => {
    if (!currentUser) return alert('Please login to like');
    const updatedPost = { ...post, likes: post.likes + 1 };
    db.updatePost(updatedPost);
    db.updateUserLikes(post.userId, 1);
    onPostUpdate(updatedPost);
  };

  const handleShare = () => {
    const updatedPost = { ...post, shares: post.shares + 1 };
    db.updatePost(updatedPost);
    onPostUpdate(updatedPost);
    // Simulate copy to clipboard
    navigator.clipboard.writeText(window.location.href);
    alert('Link copied to clipboard!');
  };

  const handleAddComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return alert('Please login to comment');
    if (!commentText.trim()) return;

    const newComment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      content: commentText,
      createdAt: new Date().toISOString()
    };

    const updatedPost = {
      ...post,
      comments: [...post.comments, newComment]
    };

    db.updatePost(updatedPost);
    onPostUpdate(updatedPost);
    setCommentText('');
  };

  return (
    <div className={`rounded-xl shadow-sm border transition-all duration-300 overflow-hidden ${
      isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200'
    }`}>
      <div className="p-6">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <img src={post.userAvatar} className="w-10 h-10 rounded-full bg-slate-200" alt={post.username} />
            <div>
              <div className="flex items-center gap-2">
                <span className="font-bold text-sm">@{post.username}</span>
                {/* Dynamically get badge based on author's context in real scenario, here we mock */}
                <BadgeIcon tier={db.getUsers().find(u => u.id === post.userId)?.badge || post.likes > 100 ? 'Gold' as any : 'Novice' as any} />
              </div>
              <span className="text-[10px] text-slate-500 uppercase font-bold tracking-tight">
                {new Date(post.createdAt).toLocaleDateString()}
              </span>
            </div>
          </div>
          <button className="text-slate-400 hover:text-indigo-500">
            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 8c1.1 0 2-.9 2-2s-.9-2-2-2-2 .9-2 2 .9 2 2 2zm0 2c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2zm0 6c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2z"/></svg>
          </button>
        </div>

        <h3 className={`font-serif text-xl font-bold mb-3 ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>
          {post.title}
        </h3>

        <p className={`text-sm leading-relaxed mb-6 ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
          {post.content}
        </p>

        <div className={`flex items-center gap-6 pt-4 border-t ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}`}>
          <button 
            onClick={handleLike}
            className="flex items-center gap-1.5 text-sm font-medium text-slate-500 hover:text-red-500 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/></svg>
            <span>{post.likes}</span>
          </button>

          <button 
            onClick={() => setShowComments(!showComments)}
            className="flex items-center gap-1.5 text-sm font-medium text-slate-500 hover:text-blue-500 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
            <span>{post.comments.length}</span>
          </button>

          <button 
            onClick={handleShare}
            className="flex items-center gap-1.5 text-sm font-medium text-slate-500 hover:text-emerald-500 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"/></svg>
            <span>{post.shares}</span>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-6 border-t ${isDarkMode ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-4 mb-6">
            {post.comments.length === 0 ? (
              <p className="text-xs text-center text-slate-500 italic">No comments yet. Be the first to share your thoughts!</p>
            ) : (
              post.comments.map(c => (
                <div key={c.id} className="flex gap-3">
                  <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold text-xs uppercase">
                    {c.username[0]}
                  </div>
                  <div className={`p-3 rounded-2xl flex-1 text-sm ${isDarkMode ? 'bg-slate-800' : 'bg-white shadow-sm'}`}>
                    <div className="flex justify-between mb-1">
                      <span className="font-bold">@{c.username}</span>
                      <span className="text-[10px] text-slate-500">{new Date(c.createdAt).toLocaleTimeString()}</span>
                    </div>
                    <p className={isDarkMode ? 'text-slate-300' : 'text-slate-600'}>{c.content}</p>
                  </div>
                </div>
              ))
            )}
          </div>

          <form onSubmit={handleAddComment} className="flex gap-2">
            <input
              type="text"
              placeholder="Write a comment..."
              value={commentText}
              onChange={(e) => setCommentText(e.target.value)}
              className={`flex-1 px-4 py-2 rounded-full text-sm outline-none transition-all ${
                isDarkMode 
                  ? 'bg-slate-800 border-slate-700 focus:border-indigo-500' 
                  : 'bg-white border-slate-200 focus:border-blue-500 border'
              }`}
            />
            <button 
              type="submit"
              className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full text-sm font-bold transition-colors"
            >
              Post
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { PostCard } from './components/PostCard';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'my-stories'>('home');
  const [searchQuery, setSearchQuery] = useState('');

  // Post form state
  const [newTitle, setNewTitle] = useState('');
  const [newContent, setNewContent] = useState('');

  // Login form state
  const [loginUsername, setLoginUsername] = useState('');

  useEffect(() => {
    setCurrentUser(db.getCurrentUser());
    setPosts(db.getPosts());

    // Particles background
    const particlesCount = 30;
    const body = document.body;
    for(let i=0; i<particlesCount; i++) {
        const p = document.createElement('div');
        p.className = 'particle';
        p.style.left = Math.random() * 100 + 'vw';
        p.style.top = Math.random() * 100 + 'vh';
        p.style.animationDelay = Math.random() * 5 + 's';
        p.style.opacity = (Math.random() * 0.5 + 0.1).toString();
        body.appendChild(p);
    }
  }, []);

  const filteredPosts = useMemo(() => {
    let result = posts;
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!loginUsername) return;
    const user = db.login(loginUsername);
    setCurrentUser(user);
    setCurrentPage('home');
    setLoginUsername('');
  };

  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const newPost: Post = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      title: newTitle,
      content: newContent,
      likes: 0,
      shares: 0,
      comments: [],
      createdAt: new Date().toISOString(),
      userAvatar: currentUser.avatar
    };

    db.savePost(newPost);
    setPosts(db.getPosts());
    setNewTitle('');
    setNewContent('');
    setCurrentPage('home');
  };

  const handlePostUpdate = (updatedPost: Post) => {
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={setCurrentPage}
      />

      <main className="max-w-4xl mx-auto px-4 py-12">
        {currentPage === 'home' || currentPage === 'my-stories' ? (
          <section className="space-y-8">
            <div className="text-center mb-12">
              <h1 className="font-serif text-4xl md:text-5xl font-bold mb-4">
                {currentPage === 'my-stories' ? 'Your Stories' : 'Latest Stories & Novels'}
              </h1>
              <p className="text-slate-500 max-w-lg mx-auto">
                {currentPage === 'my-stories' 
                  ? 'Review and manage the posts you have authored.'
                  : 'Explore the worlds created by our talented writers'}
              </p>
            </div>

            {filteredPosts.length === 0 ? (
              <div className={`p-16 border-2 border-dashed rounded-3xl text-center ${isDarkMode ? 'border-slate-800' : 'border-slate-200 bg-white shadow-xl'}`}>
                <h2 className="text-3xl font-serif font-bold mb-2">No Stories Yet</h2>
                <p className="text-slate-500 mb-8">Be the first to share your creative masterpiece!</p>
                <button 
                  onClick={() => currentUser ? setCurrentPage('create') : setCurrentPage('login')}
                  className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold shadow-lg shadow-blue-500/30 transition-all hover:-translate-y-1"
                >
                  Create Your First Story
                </button>
              </div>
            ) : (
              <div className="grid gap-8">
                {filteredPosts.map(post => (
                  <PostCard 
                    key={post.id} 
                    post={post} 
                    currentUser={currentUser} 
                    isDarkMode={isDarkMode} 
                    onPostUpdate={handlePostUpdate}
                  />
                ))}
              </div>
            )}
          </section>
        ) : currentPage === 'create' ? (
          <section className="animate-in fade-in slide-in-from-bottom-4 duration-500">
             <div className="text-center mb-10">
                <h1 className="font-serif text-4xl font-bold mb-4 uppercase tracking-wider">Share Your Story</h1>
                <p className="text-slate-500">Craft a new post and inspire the community with your words.</p>
             </div>
             <form 
              onSubmit={handleCreatePost}
              className={`p-8 rounded-3xl shadow-2xl space-y-6 ${isDarkMode ? 'bg-[#2A2E3D]' : 'bg-white'}`}
             >
                <div>
                  <label className="block text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">Title</label>
                  <input 
                    required
                    type="text" 
                    placeholder="Enter your post title here..."
                    value={newTitle}
                    onChange={(e) => setNewTitle(e.target.value)}
                    className={`w-full p-4 rounded-xl border-2 outline-none transition-all ${
                      isDarkMode 
                        ? 'bg-slate-800 border-slate-700 focus:border-indigo-500' 
