          </form>
        </div>
      )}
    </div>
  );
};

import React, { useState, useCallback, useMemo } from 'react';
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, currentUser, isDarkMode, onPostUpdate }) => {
  const [commentText, setCommentText] = useState('');
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [isAnimatingLike, setIsAnimatingLike] = useState(false);
  const [likeParticles, setLikeParticles] = useState<{ id: number; x: number; y: number }[]>([]);

  // We set a threshold for truncation
  const CONTENT_THRESHOLD = 250;
  const isLongContent = post.content.length > CONTENT_THRESHOLD;

  const isLiked = useMemo(() => {
    return currentUser ? post.likedBy?.includes(currentUser.id) : false;
  }, [post.likedBy, currentUser]);

  const handleLike = useCallback(() => {
    if (!currentUser) return alert('Please login to like');

    const hasLiked = post.likedBy?.includes(currentUser.id);
    const likeDelta = hasLiked ? -1 : 1;

    const newLikedBy = hasLiked 
      ? (post.likedBy || []).filter(id => id !== currentUser.id)
      : [...(post.likedBy || []), currentUser.id];

    if (!hasLiked) {
      setIsAnimatingLike(true);
      setTimeout(() => setIsAnimatingLike(false), 400);

      const newParticles = Array.from({ length: 5 }).map((_, i) => ({
        id: Date.now() + i,
        x: (Math.random() - 0.5) * 40,
        y: (Math.random() - 0.5) * 40,
      }));
      setLikeParticles(prev => [...prev, ...newParticles]);
      setTimeout(() => {
        setLikeParticles(prev => prev.filter(p => !newParticles.includes(p)));
      }, 800);
    }

    const updatedPost: Post = { 
      ...post, 
      likes: Math.max(0, post.likes + likeDelta),
      likedBy: newLikedBy
    };

    db.updatePost(updatedPost);
    db.updateUserLikes(post.userId, likeDelta);
    onPostUpdate(updatedPost);
  }, [post, currentUser, onPostUpdate]);

  const handleShare = () => {
    const updatedPost = { ...post, shares: post.shares + 1 };
    db.updatePost(updatedPost);
    onPostUpdate(updatedPost);
    navigator.clipboard.writeText(window.location.href);
    alert('Link copied to clipboard!');
  };

  const handleAddComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return alert('Please login to comment');
    if (!commentText.trim()) return;

    const newComment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      content: commentText,
      createdAt: new Date().toISOString()
    };

    const updatedPost = {
      ...post,
      comments: [...post.comments, newComment]
    };

    db.updatePost(updatedPost);
    onPostUpdate(updatedPost);
    setCommentText('');
  };

  const authorBadge = useMemo(() => {
    const users = db.getUsers();
    return users.find(u => u.id === post.userId)?.badge || BadgeTier.NOVICE;
  }, [post.userId, post.likes]);

  return (
    <div className={`rounded-2xl shadow-sm border transition-all duration-500 overflow-hidden h-fit flex flex-col ${
      isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200'
    }`}>
      <div className="p-6 flex-1">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <img src={post.userAvatar} className="w-10 h-10 rounded-full bg-slate-200 border-2 border-transparent hover:border-indigo-500 transition-colors" alt={post.username} />
            <div>
              <div className="flex items-center gap-2">
                <span className="font-bold text-sm hover:text-indigo-500 cursor-pointer">@{post.username}</span>
                <BadgeIcon tier={authorBadge} />
              </div>
              <span className="text-[10px] text-slate-500 uppercase font-bold tracking-tight">
                {new Date(post.createdAt).toLocaleDateString(undefined, { month: 'long', day: 'numeric', year: 'numeric' })}
              </span>
            </div>
          </div>
          <button className="text-slate-400 hover:text-indigo-500 transition-colors">
            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 8c1.1 0 2-.9 2-2s-.9-2-2-2-2 .9-2 2 .9 2 2 2zm0 2c-1.1 0-2 .9-2 2 s.9 2 2 2 2-.9 2-2-.9-2-2-2zm0 6c-1.1 0-2 .9-2 2 s.9 2 2 2 2-.9 2-2-.9-2-2-2z"/></svg>
          </button>
        </div>

        <h3 className={`font-serif text-2xl font-bold mb-4 ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>
          {post.title}
        </h3>

        <div className="relative mb-4">
          {/* whitespace-pre-wrap is essential for stories to preserve line breaks and formatting */}
          <p className={`text-base leading-relaxed whitespace-pre-wrap transition-all duration-500 ${
            isDarkMode ? 'text-slate-300' : 'text-slate-600'
          }`}>
            {isExpanded || !isLongContent 
              ? post.content 
              : `${post.content.substring(0, CONTENT_THRESHOLD)}...`}
          </p>

          {!isExpanded && isLongContent && (
            <div className={`absolute bottom-0 left-0 right-0 h-12 bg-gradient-to-t pointer-events-none ${
              isDarkMode ? 'from-slate-800' : 'from-white'
            } to-transparent opacity-60`}></div>
          )}
        </div>

        {isLongContent && (
          <button 
            onClick={() => setIsExpanded(!isExpanded)}
            className={`text-sm font-bold flex items-center gap-1 transition-all group mb-6 ${
              isDarkMode ? 'text-indigo-400 hover:text-indigo-300' : 'text-indigo-600 hover:text-indigo-700'
            }`}
          >
            <span>{isExpanded ? 'Show less' : 'Read the full story'}</span>
            <svg 
              className={`w-4 h-4 transition-transform duration-300 ${isExpanded ? 'rotate-180' : 'group-hover:translate-y-0.5'}`} 
              fill="none" 
              stroke="currentColor" 
              viewBox="0 0 24 24"
            >
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"/>
            </svg>
          </button>
        )}

        <div className={`flex items-center gap-6 pt-5 border-t ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}`}>
          <div className="relative inline-flex items-center">
            <button 
              onClick={handleLike}
              className={`group flex items-center gap-2 text-sm font-semibold transition-all ${
                isLiked || isAnimatingLike ? 'text-red-500' : 'text-slate-500 hover:text-red-500'
              }`}
            >
              <div className={`relative ${isAnimatingLike ? 'animate-heart-pop' : ''}`}>
                <svg 
                  className={`w-6 h-6 transition-all ${isLiked || isAnimatingLike ? 'fill-red-500 stroke-red-500' : 'fill-none stroke-current'}`} 
                  viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
                </svg>
              </div>
              <span className={isLiked || isAnimatingLike ? 'font-bold' : ''}>{post.likes}</span>
            </button>
            {likeParticles.map(p => (
              <div 
                key={p.id} 
                className="like-particle"
                style={{ 
                  left: '12px', 
                  top: '-4px', 
                  marginLeft: `${p.x}px`, 
                  marginTop: `${p.y}px` 
                }}
              >
                <svg className="w-3 h-3 text-red-500 fill-current" viewBox="0 0 24 24">
                  <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
                </svg>
              </div>
            ))}
          </div>

          <button 
            onClick={() => setShowComments(!showComments)}
            className={`flex items-center gap-2 text-sm font-semibold transition-colors ${
              showComments ? 'text-blue-500' : 'text-slate-500 hover:text-blue-500'
            }`}
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/>
            </svg>
            <span>{post.comments.length}</span>
          </button>

          <button 
            onClick={handleShare}
            className="flex items-center gap-2 text-sm font-semibold text-slate-500 hover:text-emerald-500 transition-colors ml-auto"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"/>
            </svg>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-6 border-t animate-in slide-in-from-top-2 duration-300 ${isDarkMode ? 'bg-slate-900/40 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-4 mb-6">
            {post.comments.length === 0 ? (
              <div className="text-center py-4">
                <p className="text-xs text-slate-500 italic">No comments yet. Start the conversation!</p>
              </div>
            ) : (
              post.comments.map(c => (
                <div key={c.id} className="flex gap-3 animate-in fade-in slide-in-from-bottom-1">
                  <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold text-xs uppercase shrink-0">
                    {c.username[0]}
                  </div>
                  <div className={`p-3 rounded-2xl flex-1 text-sm ${isDarkMode ? 'bg-slate-800' : 'bg-white shadow-sm'}`}>
                    <div className="flex justify-between mb-1">
                      <span className="font-bold">@{c.username}</span>
                      <span className="text-[10px] text-slate-500">{new Date(c.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
