            className={`w-full pl-4 pr-10 py-2 rounded-lg border outline-none transition-all ${
              isDarkMode 
                ? 'bg-slate-800 border-slate-700 text-white focus:border-indigo-500' 
                : 'bg-slate-50 border-slate-200 focus:border-blue-500'
