export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

// Helper for simulating minor network delay to ensure async UI patterns
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

export const db = {
  async getPosts(): Promise<Post[]> {
    await delay(150);
    const data = localStorage.getItem(POSTS_KEY);
    if (!data) {
      localStorage.setItem(POSTS_KEY, JSON.stringify(INITIAL_POSTS));
      return INITIAL_POSTS;
    }
    const posts = JSON.parse(data);
    return posts.map((p: any) => ({ ...p, likedBy: p.likedBy || [] }));
  },

  async savePost(post: Post): Promise<void> {
    await delay(300);
    const posts = await this.getPosts();
    posts.unshift(post);
    localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
  },

  async updatePost(updatedPost: Post): Promise<void> {
    await delay(200);
    const posts = await this.getPosts();
    const index = posts.findIndex(p => p.id === updatedPost.id);
    if (index !== -1) {
      posts[index] = updatedPost;
      localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
    }
  },

  async getUsers(): Promise<User[]> {
    await delay(150);
    const data = localStorage.getItem(USERS_KEY);
    if (!data) {
      localStorage.setItem(USERS_KEY, JSON.stringify(INITIAL_USERS));
      return INITIAL_USERS;
    }
    return JSON.parse(data);
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    await delay(200);
    const users = await this.getUsers();
    const user = users.find(u => u.id === userId);
    if (user) {
      user.totalLikes += delta;
      user.badge = getBadge(user.totalLikes);
      localStorage.setItem(USERS_KEY, JSON.stringify(users));

      const session = this.getCurrentUser();
      if (session && session.id === userId) {
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      }
    }
  },

  getCurrentUser(): User | null {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    await delay(500);
    const users = await this.getUsers();

    if (users.find(u => u.username.toLowerCase() === username.toLowerCase())) {
      return { success: false, error: 'Username already taken' };
    }
    if (users.find(u => u.email.toLowerCase() === email.toLowerCase())) {
      return { success: false, error: 'Email already registered' };
    }

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      username,
      email,
      password,
      avatar: `https://picsum.photos/seed/${username}/100`,
      totalLikes: 0,
      badge: BadgeTier.NOVICE
    };

    users.push(newUser);
    localStorage.setItem(USERS_KEY, JSON.stringify(users));
    localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));
    return { success: true, user: newUser };
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    await delay(500);
    const users = await this.getUsers();
    const user = users.find(u => {
      if (method === 'username') {
        return u.username.toLowerCase() === identifier.toLowerCase();
      } else {
        return u.email.toLowerCase() === identifier.toLowerCase();
      }
    });

    if (!user) return { success: false, error: 'Account not found' };
    if (user.password !== password) return { success: false, error: 'Invalid password' };

    localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return { success: true, user };
  },

  logout() {
    localStorage.removeItem(SESSION_KEY);
  },

  // Permanent Database Management Logic
  async exportDatabase(): Promise<string> {
    const posts = await this.getPosts();
    const users = await this.getUsers();
    const data = {
      posts,
      users,
      version: '1.0',
      exportedAt: new Date().toISOString()
    };
    return JSON.stringify(data, null, 2);
  },

  async importDatabase(jsonString: string): Promise<boolean> {
    try {
      const data = JSON.parse(jsonString);
      if (data.posts && data.users) {
        localStorage.setItem(POSTS_KEY, JSON.stringify(data.posts));
        localStorage.setItem(USERS_KEY, JSON.stringify(data.users));
        return true;
      }
      return false;
    } catch (e) {
      console.error('Import failed:', e);
      return false;
    }
  },

  async clearDatabase(): Promise<void> {
    localStorage.removeItem(POSTS_KEY);
    localStorage.removeItem(USERS_KEY);
    localStorage.removeItem(SESSION_KEY);
  }
};

import React, { useState } from 'react';
import { db } from '../services/db';

interface DatabaseSettingsProps {
  isDarkMode: boolean;
  onDataReset: () => void;
}

export const DatabaseSettings: React.FC<DatabaseSettingsProps> = ({ isDarkMode, onDataReset }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [importError, setImportError] = useState('');

  const handleExport = async () => {
    setIsExporting(true);
    const data = await db.exportDatabase();
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `storyverse_db_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    setIsExporting(false);
  };

  const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const content = event.target?.result as string;
      const success = await db.importDatabase(content);
      if (success) {
        alert('Database restored successfully! Re-syncing...');
        onDataReset();
      } else {
        setImportError('Invalid backup file. Please ensure it is a valid StoryVerse JSON.');
      }
    };
    reader.readAsText(file);
  };

  const handleReset = async () => {
    if (window.confirm('WARNING: This will permanently delete ALL stories, profiles, and data on this device. Do you wish to proceed?')) {
      await db.clearDatabase();
      onDataReset();
    }
  };

  return (
    <div className={`p-8 rounded-2xl border transition-all ${
      isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-xl'
    }`}>
      <div className="flex items-center gap-4 mb-8">
        <div className="p-3 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-xl">
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 7v10c0 2.21 3.582 4 8 4s8-1.79 8-4V7M4 7c0 2.21 3.582 4 8 4s8-1.79 8-4M4 7c0-2.21 3.582-4 8-4s8 1.79 8 4m0 5c0 2.21-3.582 4-8 4s-8-1.79-8-4" />
          </svg>
        </div>
        <div>
          <h2 className="text-2xl font-bold">Database Management</h2>
          <p className="text-sm text-slate-500">Your data is stored locally in your browser's persistent storage.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className={`p-6 rounded-xl border ${isDarkMode ? 'border-slate-800' : 'bg-slate-50 border-slate-200'}`}>
          <h3 className="text-lg font-bold mb-2">Secure Backup</h3>
          <p className="text-sm text-slate-500 mb-6 leading-relaxed">
            Download a permanent copy of your database. Use this to transfer your stories to a new browser or keep a safe off-site backup.
          </p>
          <button 
            onClick={handleExport}
            disabled={isExporting}
            className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl transition-all shadow-md active:scale-95"
          >
            {isExporting ? 'Packaging Data...' : 'Export JSON Backup'}
          </button>
        </div>

        <div className={`p-6 rounded-xl border ${isDarkMode ? 'border-slate-800' : 'bg-slate-50 border-slate-200'}`}>
          <h3 className="text-lg font-bold mb-2">Restore Database</h3>
          <p className="text-sm text-slate-500 mb-6 leading-relaxed">
            Restore your entire history from a previously exported file. This will overwrite existing local data with the backup contents.
          </p>
          <label className="block w-full py-3 bg-white dark:bg-slate-800 border-2 border-dashed border-slate-300 dark:border-slate-700 text-slate-500 hover:border-indigo-500 dark:hover:border-indigo-500 text-center font-bold rounded-xl cursor-pointer transition-all">
            Upload Backup File
            <input type="file" accept=".json" onChange={handleImport} className="hidden" />
          </label>
          {importError && <p className="text-xs text-red-500 mt-2 text-center font-medium">{importError}</p>}
        </div>
      </div>

      <div className="mt-12 pt-8 border-t border-slate-200 dark:border-slate-800">
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
          <div>
            <h3 className="font-bold text-red-500">Factory Reset</h3>
            <p className="text-sm text-slate-500">Clear all stories, users, and settings from this browser's cache.</p>
          </div>
          <button 
            onClick={handleReset}
            className="px-8 py-3 border-2 border-red-500 text-red-500 hover:bg-red-500 hover:text-white font-bold rounded-xl transition-all active:scale-95"
          >
            Delete All Data
          </button>
        </div>
      </div>
    </div>
  );
};

