import React, { useState, useEffect, useMemo } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { AuthForm } from './components/AuthForm';
import { CreatePostForm } from './components/CreatePostForm';
import { PostList } from './components/PostList';
import { Profile } from './components/Profile';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'register' | 'my-stories' | 'profile'>('home');
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  const fetchPosts = async () => {
    setIsLoading(true);
    const data = await db.getPosts();
    setPosts(data);
    setIsLoading(false);
  };

  useEffect(() => {
    const user = db.getCurrentUser();
    if (user) setCurrentUser(user);
    fetchPosts();
  }, []);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
  };

  const handleAuthSuccess = (user: User) => {
    setCurrentUser(user);
    setCurrentPage('home');
  };

  const handlePostUpdate = async (updatedPost: Post) => {
    await db.updatePost(updatedPost);
    const data = await db.getPosts();
    setPosts(data);

    // Silently update current user stats in background
    const updatedUser = db.getCurrentUser();
    if (updatedUser) setCurrentUser(updatedUser);
  };

  const handlePostCreated = async () => {
    await fetchPosts();
    setCurrentPage('home');
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={(page) => setCurrentPage(page)}
      />

      <main className="max-w-4xl mx-auto px-4 py-12">
        {isLoading && (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Accessing Secure Storage...</p>
          </div>
        )}

        {!isLoading && (currentPage === 'home' || currentPage === 'my-stories') && (
          <PostList 
            posts={filteredPosts}
            currentUser={currentUser}
            isDarkMode={isDarkMode}
            onPostUpdate={handlePostUpdate}
            onActionClick={() => currentUser ? setCurrentPage('create') : setCurrentPage('login')}
            title={currentPage === 'my-stories' ? 'Personal Archives' : 'Discover the Verse'}
            description={currentPage === 'my-stories' ? 'A private collection of your digital echoes.' : 'Where the world shares its hidden stories.'}
          />
        )}

        {currentPage === 'create' && currentUser && (
          <CreatePostForm 
            currentUser={currentUser}
            isDarkMode={isDarkMode}
            onPostCreated={handlePostCreated}
          />
        )}

        {currentPage === 'profile' && currentUser && (
          <Profile 
            user={currentUser}
            posts={posts}
            isDarkMode={isDarkMode}
          />
        )}

        {(currentPage === 'login' || currentPage === 'register') && (
          <AuthForm 
            mode={currentPage}
            isDarkMode={isDarkMode}
            onAuthSuccess={handleAuthSuccess}
            onSwitchMode={(mode) => setCurrentPage(mode)}
          />
        )}
      </main>

      <footer className={`py-12 border-t text-center transition-colors ${isDarkMode ? 'border-slate-800 text-slate-500' : 'border-slate-100 text-slate-400'}`}>
        <p className="font-serif text-lg font-bold mb-3">StoryVerse</p>
        <div className="flex items-center justify-center gap-4 text-[10px] font-black uppercase tracking-[0.2em] mb-6">
          <span className="flex items-center gap-1.5 text-emerald-500">
            <span className="w-2 h-2 bg-current rounded-full animate-pulse"></span>
            Sync Active: Local Permanent Backend
          </span>
        </div>
        <p className="text-[10px] opacity-60">© {new Date().getFullYear()} StoryVerse Collective. All stories are stored permanently in your local vault.</p>
      </footer>
    </div>
  );
};

export default App;

import { createClient } from '@supabase/supabase-js';
import { Post, User, BadgeTier, Comment } from '../types';

/**
 * SUPABASE TABLE SCHEMA:
 * 
 * 1. users: id(text, pk), username(text, unique), email(text, unique), password(text), avatar(text), total_likes(int), badge(text)
 * 2. posts: id(text, pk), user_id(text, fk), username(text), title(text), content(text), likes(int), liked_by(text[]), shares(int), user_avatar(text), created_at(timestamptz)
 * 3. comments: id(text, pk), post_id(text, fk), user_id(text, fk), username(text), content(text), created_at(timestamptz)
 */

const SUPABASE_URL = (process.env as any).SUPABASE_URL || 'https://your-project-url.supabase.co';
const SUPABASE_ANON_KEY = (process.env as any).SUPABASE_ANON_KEY || 'your-anon-key';

const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

export const db = {
  async getPosts(): Promise<Post[]> {
    const { data, error } = await supabase
      .from('posts')
      .select(`
        *,
        comments (*)
      `)
      .order('created_at', { ascending: false });

    if (error) {
      console.error('Error fetching posts:', error);
      return [];
    }

    return data.map(post => ({
      id: post.id,
      userId: post.user_id,
      username: post.username,
      title: post.title,
      content: post.content,
      likes: post.likes || 0,
      likedBy: post.liked_by || [],
      shares: post.shares || 0,
      createdAt: post.created_at,
      userAvatar: post.user_avatar,
      comments: (post.comments || []).map((c: any) => ({
        id: c.id,
        userId: c.user_id,
        username: c.username,
        content: c.content,
        createdAt: c.created_at
      }))
    }));
  },

  async savePost(post: Post): Promise<void> {
    const { error } = await supabase
      .from('posts')
      .insert([{
        id: post.id,
        user_id: post.userId,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes,
        liked_by: post.likedBy,
        shares: post.shares,
        user_avatar: post.userAvatar,
        created_at: post.createdAt
      }]);

    if (error) console.error('Error saving post:', error);
  },

  async updatePost(updatedPost: Post): Promise<void> {
    const { error } = await supabase
      .from('posts')
      .update({
        likes: updatedPost.likes,
        liked_by: updatedPost.likedBy,
        shares: updatedPost.shares,
        title: updatedPost.title,
        content: updatedPost.content
      })
      .eq('id', updatedPost.id);

    if (error) console.error('Error updating post:', error);
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    const { error } = await supabase
      .from('comments')
      .insert([{
        id: comment.id,
        post_id: postId,
        user_id: comment.userId,
        username: comment.username,
        content: comment.content,
        created_at: comment.createdAt
      }]);

    if (error) console.error('Error adding comment:', error);
  },

  async getUsers(): Promise<User[]> {
    const { data, error } = await supabase.from('users').select('*');
    if (error) {
      console.error('Error fetching users:', error);
      return [];
    }
    return data.map(u => ({
      id: u.id,
      username: u.username,
      email: u.email,
      avatar: u.avatar,
      totalLikes: u.total_likes,
      badge: u.badge as BadgeTier
    }));
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    const { data: user, error: fetchError } = await supabase
      .from('users')
      .select('*')
      .eq('id', userId)
      .single();

    if (fetchError || !user) return;

    const newTotalLikes = user.total_likes + delta;
    const newBadge = getBadge(newTotalLikes);

    const { error } = await supabase
      .from('users')
      .update({
        total_likes: newTotalLikes,
        badge: newBadge
      })
      .eq('id', userId);

    if (error) {
      console.error('Error updating user likes:', error);
    } else {
      const session = this.getCurrentUser();
      if (session && session.id === userId) {
        const updatedSessionUser = { ...session, totalLikes: newTotalLikes, badge: newBadge };
        localStorage.setItem(SESSION_KEY, JSON.stringify(updatedSessionUser));
      }
    }
  },

  getCurrentUser(): User | null {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    const { data: existingUser } = await supabase
      .from('users')
      .select('id')
      .or(`username.ilike.${username},email.ilike.${email}`)
      .maybeSingle();

    if (existingUser) {
      return { success: false, error: 'Username or Email already exists' };
    }

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      username,
      email,
      avatar: `https://picsum.photos/seed/${username}/100`,
      totalLikes: 0,
      badge: BadgeTier.NOVICE
    };

    const { error } = await supabase
      .from('users')
      .insert([{
        id: newUser.id,
        username: newUser.username,
        email: newUser.email,
        password: password,
        avatar: newUser.avatar,
        total_likes: 0,
        badge: BadgeTier.NOVICE
      }]);

    if (error) return { success: false, error: error.message };

    localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));
    return { success: true, user: newUser };
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    const field = method === 'username' ? 'username' : 'email';

    const { data, error } = await supabase
      .from('users')
      .select('*')
      .ilike(field, identifier)
      .eq('password', password)
      .maybeSingle();

    if (error || !data) {
      return { success: false, error: 'Invalid credentials' };
    }

    const user: User = {
      id: data.id,
      username: data.username,
      email: data.email,
      avatar: data.avatar,
      totalLikes: data.total_likes,
      badge: data.badge as BadgeTier
    };

    localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return { success: true, user };
  },

  logout() {
    localStorage.removeItem(SESSION_KEY);
  }
};

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, currentUser, isDarkMode, onPostUpdate }) => {
  const [commentText, setCommentText] = useState('');
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [isAnimatingLike, setIsAnimatingLike] = useState(false);
  const [likeParticles, setLikeParticles] = useState<{ id: number; x: number; y: number }[]>([]);
  const [authorBadge, setAuthorBadge] = useState<BadgeTier>(BadgeTier.NOVICE);

  const CONTENT_THRESHOLD = 250;
  const isLongContent = post.content.length > CONTENT_THRESHOLD;

  // Sync author badge from database
  useEffect(() => {
    const fetchAuthorInfo = async () => {
      const users = await db.getUsers();
      const author = users.find(u => u.id === post.userId);
      if (author) setAuthorBadge(author.badge);
    };
    fetchAuthorInfo();
  }, [post.userId, post.likes]);

  const isLiked = useMemo(() => {
    return currentUser ? post.likedBy?.includes(currentUser.id) : false;
  }, [post.likedBy, currentUser]);

  const handleLike = useCallback(async () => {
    if (!currentUser) return alert('Please login to like');

    const hasLiked = post.likedBy?.includes(currentUser.id);
    const likeDelta = hasLiked ? -1 : 1;

    const newLikedBy = hasLiked 
      ? (post.likedBy || []).filter(id => id !== currentUser.id)
      : [...(post.likedBy || []), currentUser.id];

    if (!hasLiked) {
      setIsAnimatingLike(true);
      setTimeout(() => setIsAnimatingLike(false), 400);

      const newParticles = Array.from({ length: 5 }).map((_, i) => ({
        id: Date.now() + i,
        x: (Math.random() - 0.5) * 40,
        y: (Math.random() - 0.5) * 40,
      }));
      setLikeParticles(prev => [...prev, ...newParticles]);
      setTimeout(() => {
        setLikeParticles(prev => prev.filter(p => !newParticles.includes(p)));
      }, 800);
    }

    const updatedPost: Post = { 
      ...post, 
      likes: Math.max(0, post.likes + likeDelta),
      likedBy: newLikedBy
    };

    await db.updatePost(updatedPost);
    await db.updateUserLikes(post.userId, likeDelta);
    onPostUpdate(updatedPost);
  }, [post, currentUser, onPostUpdate]);

  const handleShare = async () => {
    const updatedPost = { ...post, shares: post.shares + 1 };
    await db.updatePost(updatedPost);
    onPostUpdate(updatedPost);
    navigator.clipboard.writeText(window.location.href);
    alert('Link copied to clipboard!');
  };

  const handleAddComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return alert('Please login to comment');
    if (!commentText.trim()) return;

    const newComment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      content: commentText,
      createdAt: new Date().toISOString()
    };

    await db.addComment(post.id, newComment);

    const updatedPost = {
      ...post,
      comments: [...post.comments, newComment]
    };

    onPostUpdate(updatedPost);
    setCommentText('');
  };

  return (
    <div className={`rounded-2xl shadow-sm border transition-all overflow-hidden h-fit flex flex-col hover:shadow-md ${
      isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'
    }`}>
      <div className="p-6 flex-1">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <img src={post.userAvatar} className="w-11 h-11 rounded-xl bg-slate-200 object-cover" alt={post.username} />
            <div>
              <div className="flex items-center gap-2 mb-0.5">
                <span className="font-bold text-sm">@{post.username}</span>
                <BadgeIcon tier={authorBadge} />
              </div>
              <span className="text-[10px] text-slate-500 uppercase font-black tracking-widest opacity-80">
                {new Date(post.createdAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
              </span>
            </div>
          </div>
          <button className="text-slate-400 hover:text-indigo-500 transition-colors p-1 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z"/></svg>
          </button>
        </div>

        <h3 className={`font-serif text-2xl font-bold mb-4 tracking-tight leading-snug ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>
          {post.title}
        </h3>

        <div className="relative">
          <p className={`text-base leading-relaxed whitespace-pre-wrap mb-4 transition-all ${
            isDarkMode ? 'text-slate-400 font-light' : 'text-slate-600'
          }`}>
            {isExpanded || !isLongContent 
              ? post.content 
              : `${post.content.substring(0, CONTENT_THRESHOLD)}...`}
          </p>

          {!isExpanded && isLongContent && (
            <div className={`absolute bottom-0 left-0 right-0 h-10 bg-gradient-to-t pointer-events-none ${
              isDarkMode ? 'from-slate-800' : 'from-white'
            } to-transparent opacity-60`}></div>
          )}
        </div>

        {isLongContent && (
          <button 
            onClick={() => setIsExpanded(!isExpanded)}
            className={`text-xs font-black uppercase tracking-widest transition-colors inline-flex items-center gap-1 ${
              isDarkMode ? 'text-indigo-400 hover:text-indigo-300' : 'text-indigo-600 hover:text-indigo-700'
            } mb-6`}
          >
            {isExpanded ? 'Collapse ↑' : 'Read Full Journey ↓'}
          </button>
        )}

        <div className={`flex items-center gap-6 pt-5 border-t ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}`}>
          <div className="relative inline-flex items-center">
            <button 
              onClick={handleLike}
              className={`group flex items-center gap-2 text-sm font-bold transition-all ${
                isLiked || isAnimatingLike ? 'text-red-500 scale-105' : 'text-slate-400 hover:text-red-500'
              }`}
            >
              <div className={`relative ${isAnimatingLike ? 'animate-heart-pop' : ''}`}>
                <svg 
                  className={`w-6 h-6 transition-all ${isLiked || isAnimatingLike ? 'fill-red-500 stroke-red-500' : 'fill-none stroke-current'}`} 
                  viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
                </svg>
              </div>
              <span className="tabular-nums">{post.likes}</span>
            </button>
            {likeParticles.map(p => (
              <div 
                key={p.id} 
                className="like-particle"
                style={{ 
                  left: '12px', 
                  top: '-4px', 
                  marginLeft: `${p.x}px`, 
                  marginTop: `${p.y}px` 
                }}
              >
                <svg className="w-3 h-3 text-red-500 fill-current" viewBox="0 0 24 24">
                  <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
                </svg>
              </div>
            ))}
          </div>

          <button 
            onClick={() => setShowComments(!showComments)}
            className="flex items-center gap-2 text-sm font-bold text-slate-400 hover:text-indigo-500 transition-colors"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
            <span className="tabular-nums">{post.comments.length}</span>
          </button>

          <button 
            onClick={handleShare}
            className="flex items-center gap-2 text-sm font-bold text-slate-400 hover:text-emerald-500 transition-colors ml-auto"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"/></svg>
            <span className="tabular-nums">{post.shares}</span>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-6 border-t animate-in slide-in-from-top-2 duration-300 ${isDarkMode ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-5 mb-6">
            {post.comments.length === 0 ? (
              <p className="text-xs text-center text-slate-500 italic py-4">The Verse is quiet here. Share your resonance.</p>
            ) : (
              post.comments.map(c => (
                <div key={c.id} className="flex gap-4">
                  <div className="w-8 h-8 rounded-lg bg-indigo-500 flex items-center justify-center text-white font-black text-[10px] uppercase shadow-sm shrink-0">
                    {c.username[0]}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-1">
                      <span className="font-bold text-xs">@{c.username}</span>
                      <span className="text-[9px] text-slate-500 uppercase font-bold">{new Date(c.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                    <p className={`text-sm leading-relaxed ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}>{c.content}</p>
                  </div>
                </div>
              ))
            )}
          </div>

          <form onSubmit={handleAddComment} className="flex gap-3">
            <input
              type="text"
              placeholder="Add your thoughts..."
              value={commentText}
              onChange={(e) => setCommentText(e.target.value)}
              className={`flex-1 px-5 py-3 rounded-xl text-sm outline-none transition-all ${
                isDarkMode 
                  ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white shadow-inner' 
                  : 'bg-white border-slate-200 focus:border-indigo-500 border text-slate-900 shadow-sm'
              }`}
            />
            <button 
              type="submit"
              disabled={!commentText.trim()}
              className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white rounded-xl text-sm font-bold transition-all shadow-md active:scale-95"
            >
              Reply
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { AuthForm } from './components/AuthForm';
import { CreatePostForm } from './components/CreatePostForm';
import { PostList } from './components/PostList';
import { Profile } from './components/Profile';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'register' | 'my-stories' | 'profile'>('home');
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  const fetchPosts = async () => {
    setIsLoading(true);
    const data = await db.getPosts();
    setPosts(data);
    setIsLoading(false);
  };

  useEffect(() => {
    const user = db.getCurrentUser();
    if (user) setCurrentUser(user);
    fetchPosts();
  }, []);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
  };

  const handleAuthSuccess = (user: User) => {
    setCurrentUser(user);
    setCurrentPage('home');
  };

  const handlePostUpdate = async (updatedPost: Post) => {
    await db.updatePost(updatedPost);
    const data = await db.getPosts();
    setPosts(data);

    // Silently update current user stats in background
    const updatedUser = db.getCurrentUser();
    if (updatedUser) setCurrentUser(updatedUser);
  };

  const handlePostCreated = async () => {
    await fetchPosts();
    setCurrentPage('home');
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={(page) => setCurrentPage(page)}
      />

      <main className="max-w-4xl mx-auto px-4 py-12">
        {isLoading && (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Connecting to Cloud Verse...</p>
          </div>
        )}

        {!isLoading && (currentPage === 'home' || currentPage === 'my-stories') && (
          <PostList 
            posts={filteredPosts}
            currentUser={currentUser}
            isDarkMode={isDarkMode}
            onPostUpdate={handlePostUpdate}
            onActionClick={() => currentUser ? setCurrentPage('create') : setCurrentPage('login')}
            title={currentPage === 'my-stories' ? 'Personal Archives' : 'Discover the Verse'}
            description={currentPage === 'my-stories' ? 'A private collection of your digital echoes.' : 'Where the world shares its hidden stories.'}
          />
        )}

        {currentPage === 'create' && currentUser && (
          <CreatePostForm 
            currentUser={currentUser}
            isDarkMode={isDarkMode}
            onPostCreated={handlePostCreated}
          />
        )}

        {currentPage === 'profile' && currentUser && (
          <Profile 
            user={currentUser}
            posts={posts}
            isDarkMode={isDarkMode}
          />
        )}

        {(currentPage === 'login' || currentPage === 'register') && (
          <AuthForm 
            mode={currentPage}
            isDarkMode={isDarkMode}
            onAuthSuccess={handleAuthSuccess}
            onSwitchMode={(mode) => setCurrentPage(mode)}
          />
        )}
      </main>

      <footer className={`py-12 border-t text-center transition-colors ${isDarkMode ? 'border-slate-800 text-slate-500' : 'border-slate-100 text-slate-400'}`}>
        <p className="font-serif text-lg font-bold mb-3">StoryVerse</p>
        <div className="flex items-center justify-center gap-4 text-[10px] font-black uppercase tracking-[0.2em] mb-6">
          <span className="flex items-center gap-1.5 text-blue-500">
            <span className="w-2 h-2 bg-current rounded-full animate-pulse"></span>
            Cloud Database: Supabase Connected
          </span>
        </div>
        <p className="text-[10px] opacity-60">© {new Date().getFullYear()} StoryVerse Collective. All stories are synchronized with the cloud.</p>
      </footer>
    </div>
  );
};

