    try {
      const { data: user, error: fetchError } = await supabase
        .from('users')
        .select('*')
        .eq('id', userId)
        .single();

      if (fetchError || !user) return;

      const newTotalLikes = (user.total_likes || 0) + delta;
      const newBadge = getBadge(newTotalLikes);

      const { error } = await supabase
        .from('users')
        .update({
          total_likes: newTotalLikes,
          badge: newBadge
        })
        .eq('id', userId);

      if (error) throw error;

      const session = this.getCurrentUser();
      if (session && session.id === userId) {
        const updatedSessionUser = { ...session, totalLikes: newTotalLikes, badge: newBadge };
        localStorage.setItem(SESSION_KEY, JSON.stringify(updatedSessionUser));
      }
    } catch (err) {
      console.error('Error updating user likes:', err);
    }
  },

  getCurrentUser(): User | null {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) {
      return { success: false, error: 'Cloud Verse is not fully linked. Check backend credentials.' };
    }
    try {
      // Check if user exists
      const { data: existingUser, error: checkError } = await supabase
        .from('users')
        .select('id')
        .or(`username.ilike.${username},email.ilike.${email}`)
        .maybeSingle();

      if (checkError) throw checkError;
      if (existingUser) {
        return { success: false, error: 'Username or Email already exists in the Verse.' };
      }

      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        username,
        email,
        avatar: `https://picsum.photos/seed/${username}/100`,
        totalLikes: 0,
        badge: BadgeTier.NOVICE
      };

      const { error: insertError } = await supabase
        .from('users')
        .insert([{
          id: newUser.id,
          username: newUser.username,
          email: newUser.email,
          password: password,
          avatar: newUser.avatar,
          total_likes: 0,
          badge: BadgeTier.NOVICE
        }]);

      if (insertError) throw insertError;

      localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));
      return { success: true, user: newUser };
    } catch (err: any) {
      console.error("Supabase Register Error:", err);
      return { 
        success: false, 
        error: err.message.includes('fetch') 
          ? 'Network connection failed. Ensure Supabase tables (users, posts, comments) are created.' 
          : err.message 
      };
    }
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) {
      return { success: false, error: 'Cloud Verse is not fully linked. Check backend credentials.' };
    }
    try {
      const field = method === 'username' ? 'username' : 'email';
      const { data, error } = await supabase
        .from('users')
        .select('*')
        .ilike(field, identifier)
        .eq('password', password)
        .maybeSingle();

      if (error) throw error;
      if (!data) return { success: false, error: 'The Verse does not recognize these credentials.' };

      const user: User = {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        totalLikes: data.total_likes,
        badge: data.badge as BadgeTier
      };

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return { success: true, user };
    } catch (err: any) {
      console.error("Supabase Login Error:", err);
      return { 
        success: false, 
        error: err.message.includes('fetch') 
          ? 'Connection to Cloud failed. Ensure Supabase project is active and tables exist.' 
          : err.message 
      };
    }
  },

  logout() {
    localStorage.removeItem(SESSION_KEY);
  }
};

